// Simple sentence-based summary (first 5 sentences)
const transcript = $json.transcript_text || '';
const sentences = transcript.split('.');
const summary = sentences.slice(0, 5).join('.').trim() + (sentences.length > 5 ? '...' : '.');
return [{ json: { ...$json, summary } }];

const meetingTitle = $json.meetingTitle || 'Meeting Summary';
const html = `<!DOCTYPE html><html><body><h2>${meetingTitle}</h2><p>${$json.summary}</p></body></html>`;
return [{ json: { ...$json, emailSubject: `Summary – ${meetingTitle}`, htmlContent: html } }];

const listId = '{{YOUR_MAILCHIMP_LIST_ID}}';
const participants = $json.participants || [];
return participants.map(p => ({json: {email: p.email, listId, htmlContent: $json.htmlContent, emailSubject: $json.emailSubject}}));
